import type { Metadata } from "next";

import "./globals.css";

export const metadata: Metadata = {
  title: "Generative Gaming",
  description: "A keyboard-driven, text-dense roguelike",
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en" className="h-full dark">
      <body className="h-full antialiased">{children}</body>
    </html>
  );
}

import { GameShell } from "@/components/GameShell";

export default function GamePage() {
  return <GameShell />;
}

"use client";

import {
  useEffect,
  useMemo,
  useState,
  type CSSProperties,
  type MouseEvent,
} from "react";

import { useGameStore } from "@/store/game-store";
import { DiaryLayer, type DiaryLayerTab } from "@/components/diary";
import { GridRegion } from "@/components/grid";
import { HudRegion } from "@/components/hud";
import { KeymapOverlay } from "@/components/keymap-overlay/KeymapOverlay";
import { MessageLogRegion } from "@/components/log";
import { ContextPanelFrame } from "@/components/panels/frame";
import { questMarkersForState } from "@/components/panels/model";
import { RunIndexScreen } from "@/components/runindex";
import {
  GLYPH_SIZE_REM,
  MESSAGE_WINDOW_SIZE,
  themeVariables,
} from "@/components/settings";
import { SettingsScreen } from "@/components/settings";
import { TitleScreen } from "@/components/title";
import { FloorTransitionOverlay } from "@/components/transition";
import { GameInputOwner } from "@/input";
import { InlineConfirmPrompt } from "@/input/InlineConfirmPrompt";
import type { Position } from "@engine/state";
import { composeDiary } from "@harness/diary";

const gridRegionClass = "min-h-0";

export function GameShell() {
  const gameState = useGameStore((state) => state.gameState);
  const screen = useGameStore((state) => state.screen);
  const settings = useGameStore((state) => state.settings);
  const activeRun = useGameStore((state) => state.activeRun);
  const runIndex = useGameStore((state) => state.runIndex);
  const terminalRun = useGameStore((state) => state.terminalRun);
  const transition = useGameStore((state) => state.transition);
  const ui = useGameStore((state) => state.ui);
  const hydratePersistence = useGameStore((state) => state.hydratePersistence);
  const startGameSession = useGameStore((state) => state.startGameSession);
  const continueActiveRun = useGameStore((state) => state.continueActiveRun);
  const openTitle = useGameStore((state) => state.openTitle);
  const openSettings = useGameStore((state) => state.openSettings);
  const openRunIndex = useGameStore((state) => state.openRunIndex);
  const updateSettings = useGameStore((state) => state.updateSettings);
  const skipTransitionTheater = useGameStore(
    (state) => state.skipTransitionTheater,
  );
  const patchUi = useGameStore((state) => state.patchUi);
  const [hoverPosition, setHoverPosition] = useState<Position | null>(null);
  const questMarkers = useMemo(
    () => (gameState === null ? [] : questMarkersForState(gameState)),
    [gameState],
  );
  const diary = useMemo(
    () => (gameState === null ? null : composeDiary({ state: gameState })),
    [gameState],
  );
  const shellStyle = themeVariables(settings.colorTheme) as CSSProperties;

  useEffect(() => {
    hydratePersistence();
  }, [hydratePersistence]);

  if (screen === "settings") {
    return (
      <div data-screen="settings" data-testid="game-state" style={shellStyle}>
        <SettingsScreen
          settings={settings}
          onBack={openTitle}
          onChange={updateSettings}
        />
      </div>
    );
  }

  if (screen === "run-index") {
    return (
      <div data-screen="run-index" data-testid="game-state" style={shellStyle}>
        <RunIndexScreen runs={runIndex} onBack={openTitle} />
      </div>
    );
  }

  if (screen !== "playing" || gameState === null) {
    return (
      <div
        data-screen={terminalRun === null ? "title" : "summary"}
        data-terminal-status={terminalRun?.run.terminalStatus ?? "none"}
        data-testid="game-state"
        style={shellStyle}
      >
        <TitleScreen
          activeRun={activeRun?.gameState ?? null}
          terminalRun={terminalRun}
          onContinue={continueActiveRun}
          onNewRun={(seed) => startGameSession({ seed })}
          onRunIndex={openRunIndex}
          onSettings={openSettings}
        />
      </div>
    );
  }

  return (
    <main
      className="grid h-screen grid-rows-[minmax(0,1fr)_7rem] gap-2 overflow-hidden p-3"
      data-depth={gameState.run.depth}
      data-diary-open={ui.diaryOpen ? "true" : "false"}
      data-input-locked={ui.inputLocked ? "true" : "false"}
      data-panel-mode={ui.contextPanelMode}
      data-screen="playing"
      data-terminal-status={gameState.run.terminalStatus}
      data-testid="game-state"
      data-transition-phase={transition?.phase ?? "none"}
      data-turn={gameState.run.turn}
      style={shellStyle}
    >
      <GameInputOwner />
      <div className="grid min-h-0 grid-cols-[minmax(0,1fr)_minmax(18rem,24rem)] gap-2">
        <div
          className="min-h-0"
          onMouseMove={(event) => setHoverPosition(positionFromGridEvent(event))}
          onMouseLeave={() => setHoverPosition(null)}
        >
          <GridRegion
            className={gridRegionClass}
            glyphSizeRem={GLYPH_SIZE_REM[settings.glyphSize]}
            markers={questMarkers}
            state={gameState}
          />
        </div>

        <div className="grid min-h-0 grid-rows-[minmax(7rem,auto)_minmax(0,1fr)] gap-2">
          <HudRegion state={gameState} />

          <ContextPanelFrame
            hoverPosition={hoverPosition}
            mode={ui.contextPanelMode}
            state={gameState}
          />
        </div>
      </div>

      <div className="relative min-h-0">
        <MessageLogRegion
          state={gameState}
          windowSize={MESSAGE_WINDOW_SIZE[settings.messageSpeed]}
        />
        <InlineConfirmPrompt confirm={ui.pendingConfirm} />
      </div>
      <KeymapOverlay open={ui.keymapOpen} />
      <FloorTransitionOverlay
        transition={transition}
        onSkip={skipTransitionTheater}
      />
      {diary !== null && (ui.diaryOpen || ui.artifactOpen) ? (
        <DiaryLayer
          activeTab={ui.artifactOpen ? "artifacts" : "diary"}
          artifactModel={null}
          artifactRunId={gameState.run.runId}
          diary={diary}
          onClose={() => patchUi({ diaryOpen: false, artifactOpen: false })}
          onSelectTab={(tab: DiaryLayerTab) =>
            patchUi({
              diaryOpen: tab === "diary",
              artifactOpen: tab === "artifacts",
            })
          }
        />
      ) : null}
    </main>
  );
}

const positionFromGridEvent = (
  event: MouseEvent<HTMLDivElement>,
): Position | null => {
  const target =
    event.target instanceof HTMLElement
      ? event.target.closest<HTMLElement>("[data-x][data-y]")
      : null;
  const x = Number.parseInt(target?.dataset.x ?? "", 10);
  const y = Number.parseInt(target?.dataset.y ?? "", 10);

  return Number.isSafeInteger(x) && Number.isSafeInteger(y)
    ? { x, y }
    : null;
};

"use client";

import { create } from "zustand";

import {
  createClientGameSession,
  type ClientGameSession,
  type ClientGameSessionStep,
} from "@/input/game-session";
import {
  DEFAULT_SETTINGS,
  loadSettings,
  saveSettings,
  type SettingsState,
} from "@/components/settings/model";
import {
  clearActiveRun,
  loadActiveRun,
  loadRunIndex,
  runIndexEntryFromState,
  saveActiveRun,
  upsertRunIndexEntry,
  type ActiveRunRecord,
  type RunIndexEntry,
} from "@/components/runindex/model";
import {
  READY_THEATER_MS,
  createDescendingTransition,
  floorIntroFromState,
  markTransitionFloorReady,
  shouldAutoEnterFloor,
  shouldResumePlay,
  startArrivalRitual,
  type FloorControllerState,
  type FloorTransitionState,
  type TransitionLatencySample,
} from "@/components/transition/model";
import type { RunAction } from "@engine/run";
import type { GameState } from "@engine/state";
import { checkActionLegality } from "@engine/turn";

export type ContextPanelMode = "inspect" | "inventory" | "quest" | "dialogue";
export type AppScreen = "title" | "playing" | "settings" | "run-index";

export type PendingConfirm = {
  readonly action: RunAction;
  readonly prompt: string;
};

export type InputFeedbackActionKind = Exclude<RunAction["kind"], "take_hoard">;

export type UiSlice = {
  readonly contextPanelMode: ContextPanelMode;
  readonly diaryOpen: boolean;
  readonly artifactOpen: boolean;
  readonly keymapOpen: boolean;
  readonly pendingConfirm: PendingConfirm | null;
  readonly inputLocked: boolean;
};

export type GameStore = {
  readonly gameState: GameState | null;
  readonly gameSession: ClientGameSession | null;
  readonly screen: AppScreen;
  readonly settings: SettingsState;
  readonly activeRun: ActiveRunRecord | null;
  readonly runIndex: readonly RunIndexEntry[];
  readonly terminalRun: GameState | null;
  readonly transition: FloorTransitionState | null;
  readonly arrivalIntroLine: string | null;
  readonly latencySamples: readonly TransitionLatencySample[];
  readonly ui: UiSlice;
  readonly hydratePersistence: () => void;
  readonly startGameSession: (options: { readonly seed: string }) => void;
  readonly continueActiveRun: () => void;
  readonly openTitle: () => void;
  readonly openSettings: () => void;
  readonly openRunIndex: () => void;
  readonly updateSettings: (settings: SettingsState) => void;
  readonly skipTransitionTheater: () => void;
  readonly setGameState: (state: GameState) => void;
  readonly dispatchAction: (action: RunAction) => ClientGameSessionStep | null;
  readonly appendInputFeedback: (
    actionKind: InputFeedbackActionKind,
    reason: string,
  ) => void;
  readonly setInputLocked: (inputLocked: boolean) => void;
  readonly patchUi: (patch: Partial<UiSlice>) => void;
};

export const defaultUi: UiSlice = {
  contextPanelMode: "inspect",
  diaryOpen: false,
  artifactOpen: false,
  keymapOpen: false,
  pendingConfirm: null,
  inputLocked: false,
};

export const useGameStore = create<GameStore>((set, get) => ({
  gameState: null,
  gameSession: null,
  screen: "title",
  settings: DEFAULT_SETTINGS,
  activeRun: null,
  runIndex: [],
  terminalRun: null,
  transition: null,
  arrivalIntroLine: null,
  latencySamples: [],
  ui: defaultUi,
  hydratePersistence: () => {
    const storage = browserStorage();
    set({
      settings: loadSettings(storage),
      activeRun: loadActiveRun(storage),
      runIndex: loadRunIndex(storage),
    });
  },
  startGameSession: ({ seed }) => {
    const gameSession = createClientGameSession({ seed });
    const activeRun = activeRunFromSession(gameSession);
    persistActiveRun(gameSession);
    gameSession.prefetchNextFloor();
    set({
      gameSession,
      gameState: gameSession.state,
      screen: "playing",
      activeRun,
      terminalRun: null,
      transition: null,
      arrivalIntroLine: null,
      ui: defaultUi,
    });
  },
  continueActiveRun: () => {
    const activeRun = get().activeRun;
    if (activeRun === null || activeRun.gameState.run.terminalStatus !== "ACTIVE") {
      return;
    }

    const gameSession = createClientGameSession({
      seed: activeRun.seed,
      restoredState: activeRun.gameState,
      restoredTraceContent: activeRun.traceContent,
    });
    gameSession.prefetchNextFloor();
    set({
      gameSession,
      gameState: activeRun.gameState,
      screen: "playing",
      terminalRun: null,
      transition: null,
      arrivalIntroLine: null,
      ui: defaultUi,
    });
  },
  openTitle: () => set({ screen: "title" }),
  openSettings: () => set({ screen: "settings" }),
  openRunIndex: () =>
    set({ screen: "run-index", runIndex: loadRunIndex(browserStorage()) }),
  updateSettings: (settings) => {
    saveSettings(browserStorage(), settings);
    set({ settings });
  },
  skipTransitionTheater: () => {
    const transition = get().transition;
    if (
      transition === null ||
      transition.phase !== "descending" ||
      !transition.floorReady
    ) {
      return;
    }

    enterResolvedFloor(get, set);
  },
  setGameState: (gameState) =>
    set((current) => {
      current.gameSession?.replaceState(gameState);
      return { gameState };
    }),
  dispatchAction: (action) => {
    const session = get().gameSession;
    if (session === null) {
      return null;
    }

    const state = get().gameState;
    if (
      state !== null &&
      action.kind === "descend" &&
      state.run.terminalStatus === "ACTIVE" &&
      checkActionLegality(state, action).status === "legal"
    ) {
      beginDescendTransition(get, set);
      return null;
    }

    const result = session.step(action);
    persistAfterStep(session, result.state, set);
    return result;
  },
  appendInputFeedback: (actionKind, reason) =>
    set((current) => {
      if (current.gameState === null) {
        return {};
      }

      const event = {
        turn: current.gameState.run.turn,
        type: "action_illegal",
        data: {
          actionKind,
          reason,
        },
      } as const satisfies GameState["log"][number];
      const gameState = {
        ...current.gameState,
        log: [...current.gameState.log, event],
      };

      current.gameSession?.replaceState(gameState);

      return { gameState };
    }),
  setInputLocked: (inputLocked) =>
    set((current) => ({
      ui: { ...current.ui, inputLocked },
    })),
  patchUi: (patch) =>
    set((current) => ({
      ui: { ...current.ui, ...patch },
    })),
}));

type StoreSet = typeof useGameStore.setState;
type StoreGet = typeof useGameStore.getState;

const beginDescendTransition = (
  get: StoreGet,
  set: StoreSet,
): void => {
  const { gameSession, gameState } = get();
  if (gameSession === null || gameState === null || get().transition !== null) {
    return;
  }

  const nextDepth = gameState.run.depth + 1;
  const startedAtMs = nowMs();
  set({
    ui: { ...get().ui, inputLocked: true },
    transition: createDescendingTransition({
      depth: nextDepth,
      whisper: floorIntroFromState(gameState),
      controllerState: "none",
      startedAtMs,
    }),
    arrivalIntroLine: null,
  });

  void resolveTransitionFloor({
    get,
    set,
    session: gameSession,
    depth: nextDepth,
    startedAtMs,
  });
};

const resolveTransitionFloor = async ({
  get,
  set,
  session,
  depth,
  startedAtMs,
}: {
  readonly get: StoreGet;
  readonly set: StoreSet;
  readonly session: ClientGameSession;
  readonly depth: number;
  readonly startedAtMs: number;
}): Promise<void> => {
  const controllerState = await session.pollFloor(depth);
  patchCurrentTransition(get, set, {
    controllerState: controllerStateForStore(controllerState),
  });

  const served = await session.resolveFloor(depth);
  const readyAtMs = nowMs();
  const transition = get().transition;
  if (
    transition === null ||
    transition.phase !== "descending" ||
    transition.depth !== depth ||
    transition.startedAtMs !== startedAtMs
  ) {
    return;
  }

  set({
    transition: markTransitionFloorReady(
      transition,
      readyAtMs,
      served.source,
    ),
  });

  const next = get().transition;
  if (next === null) {
    return;
  }

  if (shouldAutoEnterFloor(next, nowMs())) {
    enterResolvedFloor(get, set);
    return;
  }

  const delayMs = Math.max(0, READY_THEATER_MS - (nowMs() - next.startedAtMs));
  globalThis.setTimeout(() => {
    const current = get().transition;
    if (current !== null && shouldAutoEnterFloor(current, nowMs())) {
      enterResolvedFloor(get, set);
    }
  }, delayMs);
};

const enterResolvedFloor = (
  get: StoreGet,
  set: StoreSet,
): void => {
  const { gameSession, transition } = get();
  if (
    gameSession === null ||
    transition === null ||
    transition.phase !== "descending" ||
    !transition.floorReady
  ) {
    return;
  }

  const result = gameSession.step({ kind: "descend" });
  const arrivalStartedAtMs = nowMs();
  const arrivalTransition = startArrivalRitual(transition, arrivalStartedAtMs);
  const introLine = floorIntroFromState(result.state);
  const latencySample = transitionLatencySample(
    result.state,
    arrivalTransition,
    arrivalStartedAtMs,
  );
  persistActiveRun(gameSession);
  gameSession.prefetchNextFloor();
  console.info("[stairs-to-playable]", latencySample);

  set({
    gameState: result.state,
    activeRun: activeRunFromSession(gameSession),
    transition: arrivalTransition,
    arrivalIntroLine: introLine,
    latencySamples: [...get().latencySamples, latencySample],
    ui: { ...get().ui, inputLocked: true, pendingConfirm: null },
  });

  const resumeDelayMs = Math.max(
    0,
    (arrivalTransition.playableAtMs ?? nowMs()) - nowMs(),
  );
  globalThis.setTimeout(() => {
    const current = get().transition;
    if (current !== null && shouldResumePlay(current, nowMs())) {
      finishArrival(get, set);
    }
  }, resumeDelayMs);
};

const finishArrival = (
  get: StoreGet,
  set: StoreSet,
): void => {
  const { transition } = get();
  if (
    transition === null ||
    transition.phase !== "arrival" ||
    transition.servedSource === null
  ) {
    return;
  }

  set({
    transition: null,
    arrivalIntroLine: null,
    ui: { ...get().ui, inputLocked: false },
  });
};

const transitionLatencySample = (
  state: GameState,
  transition: FloorTransitionState,
  recordedAtMs: number,
): TransitionLatencySample => ({
  runId: state.run.runId,
  fromDepth: Math.max(1, transition.depth - 1),
  toDepth: transition.depth,
  stairsToPlayableMs: Math.round(recordedAtMs - transition.startedAtMs),
  controllerState: transition.controllerState,
  servedSource: transition.servedSource ?? "fallback",
  recordedAtMs,
});

const patchCurrentTransition = (
  get: StoreGet,
  set: StoreSet,
  patch: Partial<FloorTransitionState>,
): void => {
  const transition = get().transition;
  if (transition === null) {
    return;
  }

  set({ transition: { ...transition, ...patch } });

"use client";

import "@/api/director/engine-runtime-web";

import { createFallbackFloorContentProvider } from "@/api/director/fallback-provider-web";
import {
  dialogueTurnHooks,
  freezeTurnCount,
  isWorldPaused,
} from "@engine/npc";
import {
  startRun,
  stepRun,
  type FloorContentProvider,
  type FloorContent,
  type RunAction,
  type RunLoopResult,
} from "@engine/run";
import {
  serialize,
  type GameState,
} from "@engine/state";

type RunEvent = Extract<RunLoopResult, { readonly ok: true }>["events"][number];

export type ClientPrefetchState = "ready" | "in_flight" | "none";

export type ClientServedFloorSource = "generated" | "fallback";

export type ClientServedFloor = {
  readonly depth: number;
  readonly content: FloorContent;
  readonly source: ClientServedFloorSource;
};

export type ClientTraceHeader = {
  readonly recordType: "header";
  readonly protocolVersion: GameState["version"]["protocolVersion"];
  readonly engineVersion: string;
  readonly modelId: string;
  readonly contentRef: {
    readonly providerId: string;
    readonly packVersion: string;
  };
  readonly seed: string;
  readonly createdAt: string;
  readonly runId: string;
};

export type ClientTraceTurn = {
  readonly turn: number;
  readonly action: RunAction;
  readonly events: readonly RunEvent[];
  readonly stateHash: string;
};

export type ClientParsedTrace = {
  readonly header: ClientTraceHeader;
  readonly turns: readonly ClientTraceTurn[];
};

export type ClientGameSessionStep = {
  readonly state: GameState;
  readonly events: readonly RunEvent[];
};

export type ClientGameSession = {
  readonly state: GameState;
  readonly createdAt: string;
  readonly traceContent: string;
  readonly parsedTrace: ClientParsedTrace;
  readonly step: (action: RunAction) => ClientGameSessionStep;
  readonly replaceState: (state: GameState) => void;
  readonly setServedFloor: (served: ClientServedFloor) => void;
  readonly pollFloor: (depth: number) => Promise<ClientPrefetchState>;
  readonly resolveFloor: (depth: number) => Promise<ClientServedFloor>;
  readonly prefetchNextFloor: () => void;
};

export type ClientGameSessionOptions = {
  readonly seed: string;
  readonly provider?: FloorContentProvider;
  readonly restoredState?: GameState;
  readonly restoredTraceContent?: string;
};

export const createClientGameSession = ({
  seed,
  provider = createFallbackFloorContentProvider(),
  restoredState,
  restoredTraceContent,
}: ClientGameSessionOptions): ClientGameSession => {
  const floorProvider = createClientServedFloorProvider(provider);
  const started = startRun(seed, floorProvider);
  if (!started.ok) {
    throw new Error(started.error.message);
  }

  let state = restoredState ?? started.state;
  const trace =
    restoredTraceContent === undefined
      ? createClientTrace({
          seed,
          createdAt: new Date().toISOString(),
          runId: state.run.runId,
          version: state.version,
        })
      : restoreClientTrace(restoredTraceContent) ??
        createClientTrace({
          seed,
          createdAt: new Date().toISOString(),
          runId: state.run.runId,
          version: state.version,
        });
  const createdAt = trace.header.createdAt;

  return {
    get state() {
      return state;
    },
    get createdAt() {
      return createdAt;
    },
    get traceContent() {
      return trace.content;
    },
    get parsedTrace() {
      return trace.parsed;
    },
    step: (action) => {
      const before = state;
      const result = stepPlayerAction(before, action, floorProvider);
      if (!result.ok) {
        throw new Error(result.error.message);
      }

      state = appendMissingReturnedEvents(before, result.state, result.events);
      trace.recordTurn(action, { state, events: result.events });

      return {
        state,
        events: result.events,
      };
    },
    replaceState: (nextState) => {
      state = nextState;
    },
    setServedFloor: (served) => {
      floorProvider.setServedFloor(served);
    },
    pollFloor: (depth) => pollPrefetchStatus(state.run.runId, depth),
    resolveFloor: async (depth) => {
      const served = await resolvePrefetchedFloor(state.run.runId, depth, seed);
      floorProvider.setServedFloor(served);
      return served;
    },
    prefetchNextFloor: () => {
      void startPrefetchForCurrentFloor(state.run.runId, state.run.depth, trace.parsed);
    },
  };
};

type ClientServedFloorProvider = FloorContentProvider & {
  readonly setServedFloor: (served: ClientServedFloor) => void;
};

const createClientServedFloorProvider = (
  fallbackProvider: FloorContentProvider,
): ClientServedFloorProvider => {
  const servedFloors = new Map<number, ClientServedFloor>();

  return {
    getFloor: (depth, seed) => {
      const served = servedFloors.get(depth);
      if (served === undefined) {
        return fallbackProvider.getFloor(depth, seed);
      }

      servedFloors.delete(depth);
      return withSeed(served.content, seed);
    },
    setServedFloor: (served) => {
      servedFloors.set(served.depth, served);
    },
  };
};

const withSeed = (content: FloorContent, seed: string): FloorContent => ({
  ...content,
  params: {
    ...content.params,
    seed,
  },
});

const stepPlayerAction = (
  state: GameState,
  action: RunAction,
  provider: FloorContentProvider,
): RunLoopResult => {
  const turnBefore = state.run.turn;
  const result = stepRun(state, action, provider, {
    hooks: dialogueTurnHooks(),
  });

  if (!result.ok) {
    return result;
  }

  let nextState = result.state;
  const events = [...result.events];

  if (action.kind === "talk" || isWorldPaused(state) || isWorldPaused(nextState)) {
    nextState = freezeTurnCount(nextState, turnBefore);
  }

  return {
    ok: true,
    state: nextState,
    events,
  };
};

const appendMissingReturnedEvents = (
  before: GameState,
  after: GameState,
  events: readonly RunEvent[],
): GameState => {
  const appendedCount = Math.max(0, after.log.length - before.log.length);
  if (appendedCount >= events.length) {
    return after;
  }

  return {
    ...after,
    log: [...after.log, ...events.slice(appendedCount)],
  };
};

type TraceVersion = {
  readonly protocolVersion: GameState["version"]["protocolVersion"];
  readonly engineVersion: string;
};

const CONTENT_REF = {
  providerId: "fallback:old-stock",
  packVersion: "0.0.0",
} as const;

const createClientTrace = ({
  seed,
  createdAt,
  runId,
  version,
}: {
  readonly seed: string;
  readonly createdAt: string;
  readonly runId: string;
  readonly version: TraceVersion;
}) => {
  const header: ClientTraceHeader = {
    recordType: "header",
    protocolVersion: version.protocolVersion,
    engineVersion: version.engineVersion,
    modelId: "web-client",
    contentRef: CONTENT_REF,
    seed,
    createdAt,
    runId,
  };
  const turns: ClientTraceTurn[] = [];
  const lines = [JSON.stringify(header)];

  return {
    header,
    get content() {
      return `${lines.join("\n")}\n`;
    },
    get parsed(): ClientParsedTrace {
      return {
        header,
        turns: [...turns],
      };
    },
    recordTurn: (
      action: RunAction,
      result: ClientGameSessionStep,
    ): ClientTraceTurn => {
      const line: ClientTraceTurn = {
        turn: result.state.run.turn,
        action,
        events: result.events,
        stateHash: computeStateHash(result.state),
      };
      turns.push(line);
      lines.push(JSON.stringify(line));
      return line;
    },
  };
};

const restoreClientTrace = (
  content: string,
): ReturnType<typeof createClientTrace> | null => {
  const lines = content
    .split(/\r?\n/u)
    .map((line) => line.trim())
    .filter((line) => line.length > 0);
  if (lines.length === 0) {
    return null;
  }

  try {
    const header = JSON.parse(lines[0] ?? "") as ClientTraceHeader;
    if (header.recordType !== "header") {
      return null;
    }
    const turns = lines.slice(1).map((line) => JSON.parse(line) as ClientTraceTurn);
    const mutableLines = [...lines];
    const mutableTurns = [...turns];

    return {
      header,
      get content() {
        return `${mutableLines.join("\n")}\n`;
      },
      get parsed(): ClientParsedTrace {
        return {
          header,
          turns: [...mutableTurns],
        };
      },
      recordTurn: (
        action: RunAction,
        result: ClientGameSessionStep,
      ): ClientTraceTurn => {
        const line: ClientTraceTurn = {
          turn: result.state.run.turn,
          action,
          events: result.events,
          stateHash: computeStateHash(result.state),
        };
        mutableTurns.push(line);
        mutableLines.push(JSON.stringify(line));
        return line;
      },
    };
  } catch {
    return null;
  }
};

