      lines.push(`[x] ${entry.title} (completed)`);
    }
    for (const entry of log.failed) {
      lines.push(`[!] ${entry.title} (failed)`);
    }
  }

  lines.push("", "Esc to close.");
  return lines.join("\n");
};

